+        // Check if the target cell is occupied by a full-size window
+        const targetOccupant = grid.windowAtCell(clampedCol, clampedRow);
+        if (targetOccupant && targetOccupant !== windowId) {
+            const targetWindow = this._windowForId(targetOccupant);
+            if (targetWindow) {
+                // SWAP: restore the stamp, minimize the target
+                this._inputRouter.hidePreview();
+                this._scaleManager.destroyClone(metaWindow);
+                this._removeFromAllGrids(windowId);
+
+                // Get the target's grid allocation before removing
+                const targetAlloc = grid.getWindow(targetOccupant);
+
+                // Restore the dragged stamp to the target's position
+                if (metaWindow.minimized)
+                    metaWindow.unminimize();
+                this._scaleManager.autoRestore(metaWindow);
+
+                if (targetAlloc) {
+                    const rect = grid.cellToPixels(targetAlloc.col, targetAlloc.row,
+                        targetAlloc.spanCols, targetAlloc.spanRows);
+                    const geo = global.workspace_manager.get_active_workspace().get_work_area_for_monitor(monitorIndex);
+                    grid.removeWindow(targetOccupant);
+                    grid.placeWindowAt(windowId, targetAlloc.col, targetAlloc.row,
+                        targetAlloc.spanCols, targetAlloc.spanRows);
+                    metaWindow.move_resize_frame(true,
+                        geo.x + rect.x, geo.y + rect.y,
+                        rect.width, rect.height);
+                }
+
+                // Minimize the target window (triggers _onMinimizedChanged → stamp)
+                metaWindow.activate(global.get_current_time());
+                targetWindow.minimize();
+                return;
+            }
+        }
+
+        // Normal stamp drop — move stamp to new grid position
