+    /**
+     * Return the window ID occupying a given cell, or null.
+     */
+    windowAtCell(col, row) {
+        if (col < 0 || col >= this.cols || row < 0 || row >= this.rows)
+            return null;
+        return this._cells[row][col];
+    }
+
     get windowCount() { return this._windows.size; }
     getAllWindows() { return new Map(this._windows); }
